import {
  SET_USER_AVATAR_ASYNC,
  SET_USER_AVATAR_FAILED,
  SET_USER_AVATAR_PROGRESS,
  SET_USER_AVATAR_SUCCESS,
  SET_USER_PROFILE_ASYNC,
  SET_USER_PROFILE_FAILED,
  SET_USER_PROFILE_PROGRESS,
  SET_USER_PROFILE_SUCCESS,
  DELETE_ACCOUNT_ASYNC,
  DELETE_ACCOUNT_FAILED,
  DELETE_ACCOUNT_PROGRESS,
  DELETE_ACCOUNT_SUCCESS,
} from './contains';

// action saga
export const setUserAvatarAsync = (payload: { media: any }) =>
  ({ type: SET_USER_AVATAR_ASYNC, payload } as const);

export const setUserProfileAsync = (payload: { media: any }) =>
  ({ type: SET_USER_PROFILE_ASYNC, payload } as const);

export const deleteAccountAsync = () =>
  ({ type: DELETE_ACCOUNT_ASYNC } as const);

// action store
export const setUserAvatarSuccess = (payload: any) =>
  ({ type: SET_USER_AVATAR_SUCCESS, payload } as const);
export const setUserAvatarFailed = (payload: any) =>
  ({ type: SET_USER_AVATAR_FAILED, payload } as const);
export const setUserAvatarProgress = (payload: boolean) =>
  ({ type: SET_USER_AVATAR_PROGRESS, payload } as const);

export const setUserProfileSuccess = (payload: any) =>
  ({ type: SET_USER_PROFILE_SUCCESS, payload } as const);
export const setUserProfileFailed = (payload: any) =>
  ({ type: SET_USER_PROFILE_FAILED, payload } as const);
export const setUserProfileProgress = (payload: boolean) =>
  ({ type: SET_USER_PROFILE_PROGRESS, payload } as const);

export const deleteAccountSuccess = (payload: any) =>
  ({ type: DELETE_ACCOUNT_SUCCESS, payload } as const);
export const deleteAccountFailed = (payload: any) =>
  ({ type: DELETE_ACCOUNT_FAILED, payload } as const);
export const deleteAccountProgress = (payload: boolean) =>
  ({ type: DELETE_ACCOUNT_PROGRESS, payload } as const);

export const actionUser = {
  setUserAvatarAsync,
  setUserAvatarSuccess,
  setUserAvatarFailed,
  setUserAvatarProgress,
  setUserProfileAsync,
  setUserProfileSuccess,
  setUserProfileFailed,
  setUserProfileProgress,
  deleteAccountAsync,
  deleteAccountSuccess,
  deleteAccountFailed,
  deleteAccountProgress,
};

export type UserAction =
  | ReturnType<typeof setUserAvatarAsync>
  | ReturnType<typeof setUserAvatarSuccess>
  | ReturnType<typeof setUserAvatarFailed>
  | ReturnType<typeof setUserAvatarProgress>
  | ReturnType<typeof setUserProfileAsync>
  | ReturnType<typeof setUserProfileSuccess>
  | ReturnType<typeof setUserProfileFailed>
  | ReturnType<typeof setUserProfileProgress>
  | ReturnType<typeof deleteAccountAsync>
  | ReturnType<typeof deleteAccountSuccess>
  | ReturnType<typeof deleteAccountFailed>
  | ReturnType<typeof deleteAccountProgress>;
